import WebGLVectorLayerRenderer from"../renderer/webgl/VectorLayer.js";import Layer from"./Layer.js";class WebGLVectorLayer extends Layer{constructor(e){super(Object.assign({},e)),this.styleVariables_=e.variables||{},this.style_=e.style,this.hitDetectionDisabled_=!!e.disableHitDetection}createRenderer(){return new WebGLVectorLayerRenderer(this,{style:this.style_,variables:this.styleVariables_,disableHitDetection:this.hitDetectionDisabled_})}updateStyleVariables(e){Object.assign(this.styleVariables_,e),this.changed()}setStyle(e){this.style_=e,this.clearRenderer(),this.changed()}}export default WebGLVectorLayer;